vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



vec2 uv1 = (vUvOriginal-.5) * uAspect.xy;

vec2 uv6 = uv1;

float z = 6*q2*length(uv1) ;
vec2 d = -normalize(1/uv1);

vec2 rs = clamp(tan(q1*z+q27/8)*d,-8,8);

//rs *= cos(uv1.yx*q27*3) ;

vUv += rs/32;

uv6 = 2*(vec2(vRadius, length(uv1)));

//uv6 = multiply(uv6,mat2(_qa));

mus = (1/(sqrt(uv6.y-q27/18)));
//mus = 1/(length(.1*sin(22*vUv+rand_frame*6)));
